import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://forum.intervals.icu/t/api-access-to-intervals-icu/609";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Intervals.icu API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:intervals-icu",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const intervalsIcuFirewall = {",
    '  name: "intervals-icu",',
    '  description: "Intervals.icu Training API",',
    "  placeholders: {",
    `    INTERVALS_ICU_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://intervals.icu",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.INTERVALS_ICU_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Intervals.icu firewall config...");
  const ts = generateTypeScript();
  writeOutput("intervals-icu", ts, import.meta.dirname);
}
